#include <stdio.h>
#include <stdlib.h>

int msb_pos(int x) {
    int pos = 0;
    while (x >>= 1) ++pos;
    return pos;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; long long X; scanf("%d %lld", &N, &X);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        long long ops = X;
        for (int i = 0; i < N - 1 && ops > 0; ++i) {
            while (A[i] && ops > 0) {
                int b = msb_pos(A[i]);
                int mask = 1 << b;
                int j = i + 1;
                while (j < N && !(A[j] & mask)) ++j;
                if (j == N) break;
                A[i] ^= mask;
                A[j] ^= mask;
                --ops;
            }
        }
        if (ops > 0 && N == 2 && (ops & 1LL)) {
            A[N-2] ^= 1;
            A[N-1] ^= 1;
        }
        for (int i = 0; i < N; ++i) {
            printf("%d", A[i]);
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
        free(A);
    }
    return 0;
}

