                int b = 31 - __builtin_clz(A[i]); // most significant set bit
                int mask = 1 << b;
                int j = i + 1;
                while (j < N && !(A[j] & mask)) ++j;
                if (j == N) break;
                A[i] ^= mask;
                A[j] ^= mask;
                --ops;
            }
